__device__ void reg_ntt_256(
    uint64_t *regs, bool invert,
    uint64_t p,
    const uint64_t *roots, const uint64_t *iroots,
    uint64_t inv_n, int lane,
    uint64_t *smem
) {
    for(int i=0;i<EPT;i++) smem[lane*EPT+i]=regs[i];
    __syncthreads();
    if(lane==0) {
        for(int i=1,j=0;i<NTT_N;i++) {
            int bit=NTT_N>>1;
            for(;j&bit;bit>>=1) j^=bit;
            j^=bit;
            if(i<j) {uint64_t t=smem[i];smem[i]=smem[j];smem[j]=t;}
        }
    }
    __syncthreads();
    for(int i=0;i<EPT;i++) regs[i]=smem[lane*EPT+i];
    __syncthreads();

    for(int stage=0;stage<3;stage++) {
        int span=1<<stage, group_size=span*2;
        for(int i=0;i<EPT;i++) {
            int gidx=lane*EPT+i;
            int k=gidx%group_size;
            if(k<span) {
                int w_idx=k*(NTT_N/group_size)%NTT_N;
                uint64_t w=invert?iroots[w_idx]:roots[w_idx];
                uint64_t u=regs[i], v=regs[i+span]*w%p;
                regs[i]=(u+v)%p; regs[i+span]=(u-v+p)%p;
            }
        }
    }

    for(int stage=3;stage<LOG_N;stage++) {
        int span=1<<stage, group_size=span*2;
        int delta=span/EPT;
        bool is_upper=((lane/delta)%2==0);
        uint64_t new_regs[EPT];
        for(int i=0;i<EPT;i++) {
            int gidx=lane*EPT+i;
            int k_in_span=is_upper?gidx%span:(gidx-span)%span;
            int w_idx=k_in_span*(NTT_N/group_size)%NTT_N;
            uint64_t w=invert?iroots[w_idx]:roots[w_idx];
            uint64_t partner=__shfl_xor_sync(0xffffffff,regs[i],delta);
            if(is_upper) {
                uint64_t u=regs[i], v=partner*w%p;
                new_regs[i]=(u+v)%p;
            } else {
                uint64_t u=partner, v=regs[i]*w%p;
                new_regs[i]=(u-v+p)%p;
            }
        }
        for(int i=0;i<EPT;i++) regs[i]=new_regs[i];
    }
    if(invert) for(int i=0;i<EPT;i++) regs[i]=regs[i]*inv_n%p;
}

// NTT乘法 a(LEN)*b(LEN)->c(2*LEN)
__device__ void reg_ntt_mul(
    uint32_t *a, uint32_t *b, uint32_t *c,
    uint64_t *smem, int lane
) {
    uint64_t ra1[EPT], rb1[EPT], ra2[EPT], rb2[EPT];
    for(int i=0;i<EPT;i++) {
        int idx=lane*EPT+i;
        ra1[i]=idx<LEN?a[idx]:0; rb1[i]=idx<LEN?b[idx]:0;
        ra2[i]=idx<LEN?a[idx]:0; rb2[i]=idx<LEN?b[idx]:0;
    }
    reg_ntt_256(ra1,false,P1,ROOT1,IROOT1,INV_N1,lane,smem);
    reg_ntt_256(rb1,false,P1,ROOT1,IROOT1,INV_N1,lane,smem);
    for(int i=0;i<EPT;i++) ra1[i]=ra1[i]*rb1[i]%P1;
    reg_ntt_256(ra1,true,P1,ROOT1,IROOT1,INV_N1,lane,smem);

    reg_ntt_256(ra2,false,P2,ROOT2,IROOT2,INV_N2,lane,smem);
    reg_ntt_256(rb2,false,P2,ROOT2,IROOT2,INV_N2,lane,smem);
    for(int i=0;i<EPT;i++) ra2[i]=ra2[i]*rb2[i]%P2;
    reg_ntt_256(ra2,true,P2,ROOT2,IROOT2,INV_N2,lane,smem);

    // CRT合并：并行计算，每线程负责自己的位置
    // 先把结果存到smem
    for(int i=0;i<EPT;i++) {
        smem[lane*EPT+i]       = ra1[i];
        smem[NTT_N+lane*EPT+i] = ra2[i];
    }
    __syncthreads();

    // 并行CRT：每线程处理EPT个位置
    // 但进位必须串行，用前缀和方式处理
    // 简化：用shared memory的uint64做并行乘加，lane0做进位
    uint64_t carry_acc[EPT];
    for(int i=0;i<EPT;i++) {
        int idx=lane*EPT+i;
        uint64_t r1=idx<NTT_N?smem[idx]:0;
        uint64_t r2=idx<NTT_N?smem[NTT_N+idx]:0;
        uint64_t t=(r2-r1%P2+P2)%P2*INV_P1_P2%P2;
        carry_acc[i]=r1+P1*t;  // 先不加进位
    }

    // 写回smem做进位传播
    for(int i=0;i<EPT;i++) smem[lane*EPT+i]=carry_acc[i];
    __syncthreads();

    if(lane==0) {
        uint64_t carry=0;
        for(int i=0;i<2*LEN;i++) {
            uint64_t val=smem[i]+carry;
            c[i]=(uint32_t)(val%BASE);
            carry=val/BASE;
        }
    }
    __syncthreads();
}

// 并行xR：32线程各负责x的部分行
__device__ void par_xR(
    uint32_t *x, uint32_t *R,
    uint64_t *acc,  // 3*LEN个uint64，调用前已清零
    int lane
) {
    for(int i=lane;i<2*LEN;i+=32) {
        uint64_t xi=x[i];
        if(xi==0) continue;
        for(int j=0;j<LEN;j++) {
            uint64_t prod=xi*R[j];
            atomicAdd((unsigned long long*)&acc[i+j],   prod%BASE);
            atomicAdd((unsigned long long*)&acc[i+j+1], prod/BASE);
        }
    }
    __syncthreads();
    if(lane==0) {
        for(int i=0;i<3*LEN-1;i++) {
            acc[i+1]+=acc[i]/BASE;
            acc[i]%=BASE;
        }
    }
    __syncthreads();
}

__device__ void dev_sub(uint32_t *a, uint32_t *b, uint32_t *c, int len) {
    int64_t borrow=0;
    for(int i=0;i<len;i++) {
        int64_t d=(int64_t)a[i]-b[i]-borrow;
        if(d<0){d+=BASE;borrow=1;}else borrow=0;
        c[i]=(uint32_t)d;
    }
}

__device__ int dev_geq(uint32_t *a, uint32_t *b, int len) {
    for(int i=len-1;i>=0;i--) {
        if(a[i]>b[i])return 1;
        if(a[i]<b[i])return 0;
    }
    return 1;
}

__device__ void dev_shr_q(uint64_t *acc, int k, uint32_t *out, int alen, int olen) {
    int ws=k/16, bs=k%16;
    for(int i=0;i<olen;i++) {
        int src=i+ws;
        uint64_t lo=src<alen?acc[src]>>bs:0;
        uint64_t hi=(bs>0&&src+1<alen)?(acc[src+1]<<(16-bs))&0xFFFFULL:0;
        out[i]=(uint32_t)((lo|hi)%BASE);
    }
}

// Barrett: r = x(2*LEN) mod n(LEN)
// xR用并行，qn用NTT
__device__ void barrett_par(
    uint32_t *x, uint32_t *n, uint32_t *R, uint32_t *r,
    uint64_t *acc_xR,  // 3*LEN uint64
    uint32_t *q, uint32_t *qn,
    uint64_t *smem_ntt,
    int n_bits, int lane
) {
    // 清零acc_xR
    for(int i=lane;i<3*LEN;i+=32) acc_xR[i]=0;
    __syncthreads();

    // 并行计算xR
    par_xR(x, R, acc_xR, lane);

    // q = acc_xR >> 2*n_bits
    if(lane==0) dev_shr_q(acc_xR, 2*n_bits, q, 3*LEN, LEN);
    __syncthreads();

    // qn = q*n 用NTT
    reg_ntt_mul(q, n, qn, smem_ntt, lane);

    // r = x - qn
    if(lane==0) {
        dev_sub(x, qn, r, LEN);
        for(int i=0;i<3;i++)
            if(dev_geq(r,n,LEN)) dev_sub(r,n,r,LEN);
    }
    __syncthreads();
}

// shared memory布局:
// uint32: T(L)+gcur(L)+tmp(2L)+q(L)+qn(2L)+nloc(L)+Rloc(L) = 9L*4
// uint64: acc_xR(3L) + smem_ntt(2*NTT_N) = (3*128+512)*8
// 总计: 9*128*4 + (384+512)*8 = 4608 + 7168 = 11776 bytes ≈ 11.5KB

__global__ __launch_bounds__(32, 16)
void reg_ntt_modexp_v2(
    uint32_t *g_all, uint32_t *m_all,
    uint32_t *n_all, uint32_t *R_all,
    uint32_t *out_all,
    int m_bits, int n_bits, int num_tasks
) {
    int task_id=blockIdx.x, lane=threadIdx.x;
    if(task_id>=num_tasks) return;

    uint32_t *g=g_all+task_id*LEN, *m=m_all+task_id*LEN;
    uint32_t *n=n_all+task_id*LEN, *R=R_all+task_id*LEN;
    uint32_t *out=out_all+task_id*LEN;

    extern __shared__ uint8_t smem_raw[];
    uint32_t *sm32=(uint32_t*)smem_raw;
    uint32_t *T=sm32, *gcur=sm32+LEN, *tmp=sm32+2*LEN;
    uint32_t *q=sm32+4*LEN, *qn=sm32+5*LEN;
    uint32_t *nloc=sm32+7*LEN, *Rloc=sm32+8*LEN;

    // uint64区域（对齐到8字节）
    uint64_t *sm64=(uint64_t*)(sm32+9*LEN);
    uint64_t *acc_xR=sm64;           // 3*LEN
    uint64_t *smem_ntt=sm64+3*LEN;   // 2*NTT_N

    for(int i=lane;i<LEN;i+=32) {
        T[i]=(i==0)?1:0; gcur[i]=g[i];
        nloc[i]=n[i]; Rloc[i]=R[i];
    }
    __syncthreads();

    for(int i=0;i<m_bits;i++) {
        int m_bit=(m[i/16]>>(i%16))&1;
        if(m_bit) {
            reg_ntt_mul(T,gcur,tmp,smem_ntt,lane);
            barrett_par(tmp,nloc,Rloc,T,acc_xR,q,qn,smem_ntt,n_bits,lane);
        }
        reg_ntt_mul(gcur,gcur,tmp,smem_ntt,lane);
        barrett_par(tmp,nloc,Rloc,gcur,acc_xR,q,qn,smem_ntt,n_bits,lane);
    }

    for(int i=lane;i<LEN;i+=32) out[i]=T[i];
}
